                                                            setOpenMenuId(null);
                                                        }}
                                                        className="focus-ring flex h-10 w-full items-center gap-sm rounded-md px-sm text-left text-body-sm font-semibold text-on-surface transition-colors hover:bg-surface-container"
                                                    >
                                                        <Eye size={18} strokeWidth={1.8} className="text-on-surface-variant" />
                                                        {TEXT.DETAIL_ACTION}
                                                    </button>
                                                </div>
                                            ) : null}
                                        </td>
                                    </tr>
                                ))}
                                {visibleLogs.length === 0 ? (
                                    <tr>
                                        <td colSpan={6} className="px-lg py-16 text-center text-body-md font-medium text-on-surface-variant">
                                            {TEXT.TABLE.EMPTY_PAGE}
                                        </td>
                                    </tr>
                                ) : null}
                            </tbody>
                        </table>
                    </div>

                    <footer className="flex flex-col gap-md border-t border-outline-variant/30 bg-surface-bright p-md sm:flex-row sm:items-center sm:justify-between">
                        <p className="text-body-sm text-on-surface-variant">{paginationSummary}</p>
                        <nav className="flex flex-wrap items-center justify-end gap-xs" aria-label={TEXT.TABLE.PAGE_LABEL}>
                            <button
                                type="button"
                                disabled={currentPage === 1}
                                aria-label={TEXT.TABLE.PREVIOUS_PAGE}
                                onClick={() => setCurrentPage((page) => Math.max(1, page - 1))}
                                className="grid h-8 w-8 place-items-center rounded text-on-surface-variant transition-colors hover:bg-surface-container hover:text-on-surface disabled:opacity-50"
                            >
                                <ChevronLeft size={18} strokeWidth={1.9} />
                            </button>
                            {paginationItems.map((item, index) =>
                                item === "ellipsis" ? (
                                    <span key={`ellipsis-${index}`} className="px-xs text-body-sm text-outline-variant">
                                        ...
                                    </span>
                                ) : (
                                    <button
                                        key={item}
                                        type="button"
                                        aria-label={`${TEXT.TABLE.PAGE_LABEL} ${item}`}
                                        aria-current={item === currentPage ? "page" : undefined}
                                        onClick={() => setCurrentPage(item)}
                                        className={`h-8 min-w-8 rounded px-sm text-body-sm font-medium transition-colors ${
                                            item === currentPage ? "bg-primary-container text-on-primary" : "text-on-surface-variant hover:bg-surface-container"
                                        }`}
                                    >
                                        {item}
                                    </button>
                                ),
                            )}
                            <button
                                type="button"
                                aria-label={TEXT.TABLE.NEXT_PAGE}
                                disabled={currentPage === TOTAL_PAGES}
                                onClick={() => setCurrentPage((page) => Math.min(TOTAL_PAGES, page + 1))}
                                className="grid h-8 w-8 place-items-center rounded text-on-surface-variant transition-colors hover:bg-surface-container hover:text-on-surface"
                            >
                                <ChevronRight size={18} strokeWidth={1.9} />
                            </button>
                        </nav>
                    </footer>
                </section>
            </main>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Loader2, Save, X } from "lucide-react";
import { ADMIN_AUTHOR_MANAGEMENT } from "@/constants/ui-text/admin";
import { authorService } from "@/services/author";
import type { Author, AuthorRequest } from "@/types/author";

interface AuthorModalProps {
    author: Author | null;
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

export default function AuthorModal({ author, isOpen, onClose, onSuccess }: AuthorModalProps) {
    const [name, setName] = useState("");
    const [description, setDescription] = useState("");

    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const textUI = ADMIN_AUTHOR_MANAGEMENT.MODAL;

    useEffect(() => {
        if (isOpen) {
            if (author) {
                setName(author.name);
                setDescription(author.biography || "");
            } else {
                setName("");
                setDescription("");
            }
            setError(null);
        }
    }, [isOpen, author]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            setSaving(true);
            setError(null);

            const requestData: AuthorRequest = {
                name,
                biography: description,
            };

            if (author?.id) {
                await authorService.updateAuthor(author.id, requestData);
            } else {
                await authorService.createAuthor(requestData);
            }

            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message || "Lỗi khi lưu tác giả");
        } finally {
            setSaving(false);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-ink-950/40 p-4 backdrop-blur-sm">
            <div className="relative flex w-full max-w-md flex-col overflow-hidden rounded-2xl bg-white shadow-xl">
                <div className="flex shrink-0 items-center justify-between border-b border-surface-container-high px-6 py-4">
                    <h2 className="text-[18px] font-semibold text-ink-950">{author ? textUI.TITLE_EDIT : textUI.TITLE_ADD}</h2>
                    <button onClick={onClose} className="rounded-full p-1.5 text-outline transition-colors hover:bg-surface hover:text-on-surface">
                        <X size={20} />
                    </button>
                </div>

                <div className="p-6">
                    <form onSubmit={handleSubmit} className="space-y-4">
                        {error && <div className="rounded-lg bg-error-50 p-3 text-[14px] text-error">{error}</div>}

                        <div className="space-y-1.5">
                            <label className="text-[13px] font-medium text-on-surface-variant">{textUI.LABEL_NAME}</label>
                            <input
                                type="text"
                                required
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                placeholder="Ví dụ: Khoa học viễn tưởng"
                                className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                            />
                        </div>

                        <div className="space-y-1.5">
                            <label className="text-[13px] font-medium text-on-surface-variant">{textUI.LABEL_BIO}</label>
                            <textarea
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                placeholder="Mô tả ngắn gọn về tiểu sử tác giả này..."
                                rows={3}
                                className="w-full resize-none rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                            />
                        </div>

                        <div className="mt-6 flex items-center justify-end gap-3 border-t border-surface-container-high pt-4">
                            <button
                                type="button"
                                onClick={onClose}
                                className="rounded-lg px-4 py-2.5 text-[14px] font-medium text-on-surface-variant transition-colors hover:bg-surface"
                            >
                                {textUI.BTN_CANCEL}
                            </button>
                            <button
                                type="submit"
                                disabled={saving || !name.trim()}
                                className="focus-ring flex items-center gap-2 rounded-lg bg-primary-700 px-5 py-2.5 text-[14px] font-semibold text-white transition-colors hover:bg-primary-500 disabled:opacity-70"
                            >
                                {saving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                                {textUI.BTN_SAVE}
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useCallback, useEffect, useState } from "react";
import { Edit2, Feather, Loader2, Plus, Trash2 } from "lucide-react";
import { toast } from "sonner";
import { TableSkeleton } from "@/components/ui/table-skeleton";
import { ADMIN, ADMIN_AUTHOR_MANAGEMENT } from "@/constants/ui-text/admin";
import { authorService } from "@/services/author";
import type { Author } from "@/types/author";
import AuthorModal from "./AuthorModal";

export default function AuthorTable() {
    const [authors, setAuthors] = useState<Author[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingAuthor, setEditingAuthor] = useState<Author | null>(null);

    const fetchAuthors = useCallback(async () => {
        const startTime = Date.now();
        try {
            setLoading(true);
            setError(null);
            const data = await authorService.getAllAuthors();
            setAuthors(data);
        } catch (err: any) {
            const elapsed = Date.now() - startTime;
            if (elapsed < 5000) {
                await new Promise((resolve) => setTimeout(resolve, 5000 - elapsed));
            }
            setError(err.message || "Lỗi khi tải danh sách tác giả");
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchAuthors();
    }, [fetchAuthors]);

    const handleAdd = () => {
        setEditingAuthor(null);
        setIsModalOpen(true);
    };

    const handleEdit = (author: Author) => {
        setEditingAuthor(author);
        setIsModalOpen(true);
    };

    const [deleteAuthorId, setDeleteAuthorId] = useState<number | null>(null);
    const [isDeleting, setIsDeleting] = useState(false);

    const deleteUI = ADMIN.MODAL.DELETE_AUTHOR;
    const textUI = ADMIN_AUTHOR_MANAGEMENT;

    const handleDeleteClick = (id: number) => {
        setDeleteAuthorId(id);
    };

    const confirmDelete = async () => {
        if (deleteAuthorId === null) return;

        try {
            setIsDeleting(true);
            await authorService.deleteAuthor(deleteAuthorId);
            fetchAuthors();
            setDeleteAuthorId(null);
        } catch (err: any) {
            toast.error(err.message || "Lỗi khi xoá tác giả");
        } finally {
            setIsDeleting(false);
        }
    };

    return (
        <div className="flex h-full flex-col bg-surface">
            {/* Header */}
            <div className="flex items-center justify-between border-b border-surface-container-high bg-white px-8 py-6">
                <div>
                    <h1 className="flex items-center gap-2 text-[28px] font-semibold leading-tight text-ink-950">
                        <Feather size={24} className="text-primary-600" />
                        {textUI.HEADER.TITLE}
                    </h1>
                    <p className="mt-1 text-[14px] text-on-surface-variant">{textUI.HEADER.DESCRIPTION}</p>
                </div>
                <button
                    onClick={handleAdd}
                    className="focus-ring flex items-center gap-2 rounded-lg bg-primary-700 px-4 py-2.5 text-[14px] font-semibold text-white shadow-sm transition-colors hover:bg-primary-500"
                >
                    <Plus size={18} strokeWidth={2.5} />
                    {textUI.HEADER.CREATE_BTN}
                </button>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-auto p-8">
                <div className="overflow-hidden rounded-xl border border-surface-container-high bg-white shadow-sm">
                    <table className="w-full text-left text-[14px]">
                        <thead className="border-b border-surface-container-high bg-surface-container-lowest">
                            <tr>
                                <th className="w-16 px-6 py-4 text-center font-semibold text-on-surface-variant">ID</th>
                                <th className="w-1/3 px-6 py-4 font-semibold text-on-surface-variant">{textUI.TABLE.COL_NAME}</th>
                                <th className="w-1/2 px-6 py-4 font-semibold text-on-surface-variant">{textUI.TABLE.COL_BIO}</th>
                                <th className="px-6 py-4 text-right font-semibold text-on-surface-variant">{textUI.TABLE.COL_ACTIONS}</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-surface-container-high">
                            {loading ? (
                                <TableSkeleton columns={4} rows={5} />
                            ) : error ? (
                                <tr>
                                    <td colSpan={4} className="px-6 py-12 text-center text-error">
                                        <p>{error}</p>
                                        <button onClick={fetchAuthors} className="text-primary-600 mt-2 hover:underline">
                                            {textUI.TABLE.BTN_RETRY}
                                        </button>
                                    </td>
                                </tr>
                            ) : authors.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="px-6 py-12 text-center text-outline">
                                        <Feather size={48} className="mx-auto mb-3 text-surface-container-highest" />
                                        <p>{textUI.TABLE.EMPTY_STATE}</p>
                                    </td>
                                </tr>
                            ) : (
                                authors.map((author) => (
                                    <tr key={author.id} className="transition-colors hover:bg-surface-container-lowest/50">
                                        <td className="px-6 py-4 text-center text-on-surface-variant">{author.id}</td>
                                        <td className="px-6 py-4 font-medium text-ink-950">{author.name}</td>
                                        <td className="px-6 py-4 text-on-surface-variant">
                                            {author.biography || <span className="italic text-outline-variant">{textUI.TABLE.NO_BIO}</span>}
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center justify-end gap-2">
                                                <button
                                                    onClick={() => handleEdit(author)}
                                                    className="text-primary-600 focus-ring rounded-lg p-2 transition-colors hover:bg-primary-50"
                                                    title="Sửa"
                                                >
                                                    <Edit2 size={16} />
                                                </button>
                                                <button
                                                    onClick={() => handleDeleteClick(author.id)}
                                                    className="focus-ring rounded-lg p-2 text-error transition-colors hover:bg-error-50"
                                                    title="Xoá"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            <AuthorModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} author={editingAuthor} onSuccess={fetchAuthors} />

            {/* Delete Confirmation Modal */}
            {deleteAuthorId !== null && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-ink-950/40 p-4 backdrop-blur-sm">
                    <div className="w-full max-w-sm overflow-hidden rounded-2xl bg-white shadow-xl">
                        <div className="p-6">
                            <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-error-50 text-error">
                                <Trash2 size={24} />
                            </div>
                            <h3 className="text-center text-lg font-semibold text-ink-950">{deleteUI.TITLE}</h3>
                            <p className="mt-2 text-center text-sm text-on-surface-variant">{deleteUI.DESCRIPTION}</p>
                        </div>
                        <div className="flex items-center justify-end gap-3 border-t border-surface-container-high bg-surface-container-lowest px-6 py-4">
                            <button
                                onClick={() => setDeleteAuthorId(null)}
                                className="rounded-lg px-4 py-2 text-sm font-medium text-on-surface-variant transition-colors hover:bg-surface-container-high"
                                disabled={isDeleting}
                            >
                                {deleteUI.CANCEL}
                            </button>
                            <button
                                onClick={confirmDelete}
                                className="flex w-[130px] items-center justify-center gap-2 rounded-lg bg-error px-4 py-2 text-sm font-semibold text-white transition-colors hover:bg-error-600"
                                disabled={isDeleting}
                            >
                                {isDeleting ? <Loader2 size={16} className="animate-spin" /> : deleteUI.CONFIRM}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Book, Calendar, DollarSign, User, X } from "lucide-react";
import { Skeleton } from "@/components/ui/skeleton";
import { UI_TEXT } from "@/constants/ui-text";
import { AdminBorrowOrderDetailResponse, getAdminBorrowOrderDetail } from "@/services/adminBorrow";

const T = UI_TEXT.ADMIN_BORROW_MANAGEMENT.DETAIL_MODAL;

interface BorrowDetailModalProps {
    isOpen: boolean;
    onClose: () => void;
    orderCode: string | null;
}

export default function BorrowDetailModal({ isOpen, onClose, orderCode }: BorrowDetailModalProps) {
    const [detail, setDetail] = useState<AdminBorrowOrderDetailResponse | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (isOpen && orderCode) {
            fetchDetail();
        } else {
            setDetail(null);
            setError(null);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen, orderCode]);

    const fetchDetail = async () => {
        const startTime = Date.now();
        setIsLoading(true);
        setError(null);
        try {
            const res = await getAdminBorrowOrderDetail(orderCode!);
            if (res.success && res.data) {
                setDetail(res.data);
            } else {
                const elapsed = Date.now() - startTime;
                if (elapsed < 5000) {
                    await new Promise((resolve) => setTimeout(resolve, 5000 - elapsed));
                }
                setError(res.message || "Failed to load details");
            }
        } catch (err) {
            const elapsed = Date.now() - startTime;
            if (elapsed < 5000) {
                await new Promise((resolve) => setTimeout(resolve, 5000 - elapsed));
            }
            setError("Đã có lỗi xảy ra khi tải chi tiết");
        } finally {
            setIsLoading(false);
        }
    };

    if (!isOpen) return null;

    const TRANSLATE_ORDER_STATUS: Record<string, string> = {
        PENDING: "Chờ xử lý",
        READY: "Chờ lấy sách",
        BORROWED: "Đang mượn",
        OVERDUE: "Quá hạn",
        RETURNED: "Đã trả",
        CANCELLED: "Đã hủy",
    };

    const TRANSLATE_BOOK_STATUS: Record<string, string> = {
        BORROWING: "Đang mượn",
        RETURNED: "Đã trả",
        OVERDUE: "Quá hạn",
        LOST: "Đã mất",
        CANCELLED: "Đã hủy",
        DAMAGED: "Hư hỏng",
    };

    const formatDate = (dateStr: string | null) => {
        if (!dateStr) return "N/A";
        const [year, month, day] = dateStr.split("-");
        return `${day}/${month}/${year}`;
    };

    const formatMoney = (amount: number) => {
        return new Intl.NumberFormat("vi-VN", { style: "currency", currency: "VND" }).format(amount);
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4 backdrop-blur-sm">
            <div className="flex max-h-[90vh] w-full max-w-3xl flex-col rounded-2xl bg-surface-container-lowest shadow-xl">
                {/* Header */}
                <div className="flex items-center justify-between border-b border-outline-variant/30 px-6 py-4">
                    <div>
                        <h2 className="text-xl font-bold text-on-surface">{T.TITLE}</h2>
                        {orderCode && (
                            <p className="mt-1 text-sm text-on-surface-variant">
                                {T.ORDER_CODE}
                                {orderCode}
                            </p>
                        )}
                    </div>
                    <button
                        onClick={onClose}
                        className="rounded-full p-2 text-on-surface-variant transition-colors hover:bg-surface-container-low hover:text-on-surface"
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* Body */}
                <div className="flex-1 overflow-y-auto p-6">
                    {isLoading ? (
                        <div className="flex flex-col gap-6">
                            <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
                                <Skeleton className="h-[140px] rounded-xl" />
                                <Skeleton className="h-[140px] rounded-xl" />
                            </div>
                            <div className="mt-4">
                                <Skeleton className="mb-4 h-6 w-1/3" />
                                <Skeleton className="h-16 w-full rounded-xl" />
                                <Skeleton className="mt-2 h-16 w-full rounded-xl" />
                            </div>
                        </div>
                    ) : error ? (
                        <div className="flex h-40 items-center justify-center text-error">{error}</div>
                    ) : detail ? (
                        <div className="flex flex-col gap-6">
                            {/* General Info Grid */}
                            <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
                                {/* Customer Info */}
                                <div className="rounded-xl border border-outline-variant/30 bg-surface-container-low/50 p-4">
                                    <div className="mb-3 flex items-center gap-2 font-medium text-on-surface">
                                        <User size={18} className="text-primary" />
                                        {T.SECTION_MEMBER}
                                    </div>
                                    <div className="space-y-2 text-sm">
                                        <div className="flex items-center gap-2">
                                            <span className="text-on-surface-variant">{T.MEMBER_NAME}</span>{" "}
                                            <span className="font-medium">{detail.customerName}</span>
                                            {detail.isGuest && (
                                                <span className="rounded bg-primary-100 px-1.5 py-0.5 text-[10px] font-semibold text-primary-700 dark:bg-primary-900 dark:text-primary-300">
                                                    {T.GUEST_BADGE}
                                                </span>
                                            )}
                                        </div>
                                        <p>
                                            <span className="text-on-surface-variant">{T.MEMBER_CODE}</span> <span>{detail.customerCode}</span>
                                        </p>
                                        <p>
                                            <span className="text-on-surface-variant">{T.MEMBER_PHONE}</span> <span>{detail.customerPhone}</span>
                                        </p>
                                    </div>
                                </div>

                                {/* Order Info */}
                                <div className="rounded-xl border border-outline-variant/30 bg-surface-container-low/50 p-4">
                                    <div className="mb-3 flex items-center gap-2 font-medium text-on-surface">
                                        <Calendar size={18} className="text-secondary" />
                                        {T.SECTION_BORROW_INFO}
                                    </div>
                                    <div className="space-y-2 text-sm">
                                        <p>
                                            <span className="text-on-surface-variant">{T.CREATED_AT}</span> <span>{formatDate(detail.borrowDate)}</span>
                                        </p>
                                        <p>
                                            <span className="text-on-surface-variant">{T.DUE_DATE}</span> <span>{formatDate(detail.dueDate)}</span>
                                        </p>
                                        <p>
                                            <span className="text-on-surface-variant">{T.STATUS}</span>{" "}
                                            <span className="font-medium uppercase">{TRANSLATE_ORDER_STATUS[detail.status] || detail.status}</span>
                                        </p>
                                    </div>
                                </div>
                            </div>

                            {/* Books Table */}
                            <div className="overflow-hidden rounded-xl border border-outline-variant/30">
                                <div className="flex items-center gap-2 border-b border-outline-variant/30 bg-surface-container-low px-4 py-3 font-medium text-on-surface">
                                    <Book size={18} className="text-tertiary" />
                                    {T.SECTION_BOOKS}
                                </div>
                                <div className="overflow-x-auto">
                                    <table className="w-full text-left text-sm">
                                        <thead className="bg-surface-container-lowest font-medium text-on-surface-variant">
                                            <tr>
                                                <th className="px-4 py-3">{T.BOOK_TITLE}</th>
                                                <th className="px-4 py-3">{T.BOOK_AUTHOR}</th>
                                                <th className="px-4 py-3">{T.BOOK_BARCODE}</th>
                                                <th className="px-4 py-3">{T.BOOK_STATUS}</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-outline-variant/20 bg-surface-container-lowest">
                                            {detail.items.map((item) => (
                                                <tr key={item.id} className="hover:bg-surface-container-low/30">
                                                    <td className="px-4 py-3 font-medium text-on-surface">{item.bookTitle}</td>
                                                    <td className="px-4 py-3 text-on-surface-variant">{item.bookAuthor}</td>
                                                    <td className="px-4 py-3">{item.barcode}</td>
                                                    <td className="px-4 py-3 text-xs font-medium uppercase text-on-surface-variant">
                                                        {TRANSLATE_BOOK_STATUS[item.status] || item.status}
                                                    </td>
                                                </tr>
                                            ))}
                                            {detail.items.length === 0 && (
                                                <tr>
                                                    <td colSpan={4} className="px-4 py-6 text-center text-on-surface-variant">
                                                        {T.NO_BOOKS}
                                                    </td>
                                                </tr>
                                            )}
                                        </tbody>
                                    </table>
                                </div>
                            </div>

                            {/* Financial Summary */}
                            <div className="rounded-xl border border-outline-variant/30 bg-surface-container-low/50 p-4">
                                <div className="mb-3 flex items-center gap-2 font-medium text-on-surface">
                                    <DollarSign size={18} className="text-error" />
                                    {T.SECTION_FEE}
                                </div>
                                <div className="flex flex-col gap-2 text-sm">
                                    <div className="flex justify-between">
                                        <span className="text-on-surface-variant">{T.FEE_RENT}</span>
                                        <span>{formatMoney(detail.subtotalFee)}</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span className="text-on-surface-variant">{T.FEE_DISCOUNT}</span>
                                        <span>-{formatMoney(detail.discountAmount)}</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span className="text-on-surface-variant">{T.FEE_DEPOSIT}</span>
                                        <span>{formatMoney(detail.totalDeposit)}</span>
                                    </div>
                                    <div className="mt-2 flex justify-between border-t border-outline-variant/30 pt-2 text-base font-bold">
                                        <span className="text-on-surface">{T.FEE_TOTAL}</span>
                                        <span className="text-primary">{formatMoney(detail.totalFee + detail.totalDeposit)}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ) : null}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { BookOpen, CalendarDays, Loader2, User as UserIcon, X } from "lucide-react";
import { UI_TEXT } from "@/constants/ui-text";
import { createAdminBorrowOrder } from "@/services/adminBorrow";

const T = UI_TEXT.ADMIN_BORROW_MANAGEMENT.MODAL;

export default function BorrowModal({ open, onClose, onSubmitSuccess }: { open: boolean; onClose: () => void; onSubmitSuccess: () => void }) {
    const [form, setForm] = useState({
        phone: "",
        fullName: "",
        email: "",
        bookBarcodes: "",
        dueDate: "",
    });
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (open) {
            setForm({ phone: "", fullName: "", email: "", bookBarcodes: "", dueDate: "" });
            setError(null);
            setIsLoading(false);
        }
    }, [open]);

    if (!open) return null;

    const handleSubmit = async () => {
        setError(null);
        if (!form.phone.trim() || !form.bookBarcodes.trim() || !form.dueDate) {
            setError("Vui lòng điền các thông tin bắt buộc (SĐT, Mã vạch, Ngày hẹn trả)");
            return;
        }

        const barcodes = form.bookBarcodes
            .split(",")
            .map((b) => b.trim())
            .filter((b) => b.length > 0);

        if (barcodes.length === 0) {
            setError("Vui lòng nhập ít nhất một mã vạch hợp lệ");
            return;
        }

        setIsLoading(true);
        try {
            const res = await createAdminBorrowOrder({
                phone: form.phone,
                fullName: form.fullName,
                email: form.email,
                bookBarcodes: barcodes,
                dueDate: form.dueDate,
            });

            if (res.success) {
                onSubmitSuccess();
                onClose();
            } else {
                setError(res.message || "Tạo phiếu mượn thất bại");
            }
        } catch (err: any) {
            setError(err.response?.data?.message || "Đã có lỗi xảy ra");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 px-4 backdrop-blur-sm">
            <div className="level-2-shadow flex w-full max-w-lg transform flex-col overflow-hidden rounded-2xl bg-surface-container-lowest transition-all">
                {/* Header */}
                <div className="flex items-center justify-between border-b border-outline-variant/30 bg-surface-bright p-6">
                    <h3 className="text-xl font-bold text-on-background">{T.CREATE_TITLE}</h3>
                    <button
                        onClick={onClose}
                        disabled={isLoading}
                        className="rounded-full p-2 text-on-surface-variant transition-colors hover:bg-error-container/20 hover:text-error disabled:opacity-50"
                    >
                        <X size={24} />
                    </button>
                </div>

                {/* Form Body */}
                <div className="flex flex-col gap-5 p-6">
                    {error && <div className="rounded border border-error/50 bg-error-container/20 p-3 text-sm text-error">{error}</div>}
                    <div className="flex flex-col gap-1.5">
                        <label className="text-sm font-medium text-on-surface">
                            {T.LABEL_PHONE} <span className="text-error">*</span>
                        </label>
                        <div className="relative">
                            <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-outline-variant" size={20} />
                            <input
                                className="w-full rounded-lg border border-outline-variant/50 bg-surface-container-low py-2.5 pl-10 pr-4 text-sm text-on-surface transition-colors focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-70"
                                placeholder="Nhập số điện thoại..."
                                value={form.phone}
                                onChange={(e) => setForm({ ...form, phone: e.target.value })}
                                type="text"
                                disabled={isLoading}
                            />
                        </div>
                    </div>

                    <div className="flex flex-col gap-1.5">
                        <label className="text-sm font-medium text-on-surface">
                            {T.LABEL_FULL_NAME} <span className="text-xs font-normal text-on-surface-variant">{T.HINT_OPTIONAL_CREATE}</span>
                        </label>
                        <div className="relative">
                            <input
                                className="w-full rounded-lg border border-outline-variant/50 bg-surface-container-low px-4 py-2.5 text-sm text-on-surface transition-colors focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-70"
                                placeholder="Nhập họ và tên..."
                                value={form.fullName}
                                onChange={(e) => setForm({ ...form, fullName: e.target.value })}
                                type="text"
                                disabled={isLoading}
                            />
                        </div>
                    </div>

                    <div className="flex flex-col gap-1.5">
                        <label className="text-sm font-medium text-on-surface">
                            {T.LABEL_EMAIL} <span className="text-xs font-normal text-on-surface-variant">{T.HINT_OPTIONAL}</span>
                        </label>
                        <div className="relative">
                            <input
                                className="w-full rounded-lg border border-outline-variant/50 bg-surface-container-low px-4 py-2.5 text-sm text-on-surface transition-colors focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-70"
                                placeholder="Nhập email..."
                                value={form.email}
                                onChange={(e) => setForm({ ...form, email: e.target.value })}
                                type="email"
                                disabled={isLoading}
                            />
                        </div>
                    </div>

                    <div className="flex flex-col gap-1.5">
                        <label className="text-sm font-medium text-on-surface">
                            {T.LABEL_BOOK_BARCODE} <span className="text-error">*</span>
                        </label>
                        <div className="relative">
                            <BookOpen className="absolute left-3 top-1/2 -translate-y-1/2 text-outline-variant" size={20} />
                            <input
                                className="w-full rounded-lg border border-outline-variant/50 bg-surface-container-low py-2.5 pl-10 pr-4 text-sm text-on-surface transition-colors focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-70"
                                placeholder="Ví dụ: BC001, BC002..."
                                value={form.bookBarcodes}
                                onChange={(e) => setForm({ ...form, bookBarcodes: e.target.value })}
                                type="text"
                                disabled={isLoading}
                            />
                        </div>
                        <p className="text-xs text-on-surface-variant">{T.HINT_MULTIPLE_BARCODE}</p>
                    </div>

                    <div className="flex flex-col gap-1.5">
                        <label className="text-sm font-medium text-on-surface">
                            {T.LABEL_DUE_DATE} <span className="text-error">*</span>
                        </label>
                        <div className="relative">
                            <CalendarDays className="absolute left-3 top-1/2 -translate-y-1/2 text-outline-variant" size={20} />
                            <input
                                className="w-full rounded-lg border border-outline-variant/50 bg-surface-container-low py-2.5 pl-10 pr-4 text-sm text-on-surface transition-colors focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-70"
                                value={form.dueDate}
                                onChange={(e) => setForm({ ...form, dueDate: e.target.value })}
                                type="date"
                                disabled={isLoading}
                            />
                        </div>
                    </div>
                </div>

                {/* Actions Footer */}
                <div className="mt-auto flex justify-end gap-3 border-t border-outline-variant/30 bg-surface-bright p-6">
                    <button
                        onClick={onClose}
                        disabled={isLoading}
                        className="rounded-lg border border-outline px-5 py-2.5 text-sm font-medium text-on-surface transition-colors hover:bg-surface-variant disabled:opacity-50"
                    >
                        {T.BTN_CANCEL}
                    </button>
                    <button
                        onClick={handleSubmit}
                        disabled={isLoading}
                        className="flex items-center justify-center gap-2 rounded-lg bg-primary px-5 py-2.5 text-sm font-medium text-on-primary shadow-sm transition-colors hover:bg-primary/90 disabled:opacity-70"
                    >
                        {isLoading && <Loader2 className="animate-spin" size={16} />}
                        {T.BTN_CREATE}
                    </button>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { CheckCircle, ChevronLeft, ChevronRight, Eye, Mail, PackageCheck, X } from "lucide-react";
import { TableSkeleton } from "@/components/ui/table-skeleton";
import { UI_TEXT } from "@/constants/ui-text";

const T = UI_TEXT.ADMIN_BORROW_MANAGEMENT.TABLE;

export type BorrowStatus = "borrowed" | "overdue" | "ready" | "returned" | "pending" | "pending_renewal";

export type BorrowRecord = {
    id: string;
    member: {
        name: string;
        code: string;
        avatarUrl?: string;
        avatarInitials?: string;
        avatarColor?: "secondary" | "tertiary" | "primary";
    };
    book: {
        title: string;
        author: string;
        coverUrl?: string;
    };
    borrowDate: string | null;
    dueDate: string | null;
    status: BorrowStatus;
    overdayCount?: number;
    isGuest?: boolean;
};

function StatusBadge({ status, overdayCount }: { status: BorrowStatus; overdayCount?: number }) {
    switch (status) {
        case "borrowed":
            return (
                <span className="inline-flex items-center gap-1.5 rounded-full border border-secondary-fixed bg-secondary-fixed/50 px-2.5 py-1 text-xs font-medium text-on-secondary-container">
                    <span className="h-1.5 w-1.5 rounded-full bg-secondary" />
                    {T.STATUS_BORROWED}
                </span>
            );
        case "overdue":
            return (
                <span className="inline-flex items-center gap-1.5 rounded-full border border-error-container bg-error-container/50 px-2.5 py-1 text-xs font-medium text-error">
                    <span className="h-1.5 w-1.5 rounded-full bg-error" />
                    {T.STATUS_OVERDUE}
                    {overdayCount ? ` (${overdayCount} ngày)` : ""}
                </span>
            );
        case "ready":
            return (
                <span className="inline-flex items-center gap-1.5 rounded-full border border-outline-variant/50 bg-surface-container-high px-2.5 py-1 text-xs font-medium text-on-surface">
                    <span className="h-1.5 w-1.5 rounded-full bg-outline" />
                    {T.STATUS_READY}
                </span>
            );
        case "returned":
            return (
                <span className="inline-flex items-center gap-1.5 rounded-full border border-outline-variant/30 bg-surface-container px-2.5 py-1 text-xs font-medium text-on-surface-variant">
                    <span className="h-1.5 w-1.5 rounded-full bg-outline-variant" />
                    {T.STATUS_RETURNED}
                </span>
            );
        case "pending":
            return (
                <span className="inline-flex items-center gap-1.5 rounded-full border border-tertiary-fixed bg-tertiary-fixed/20 px-2.5 py-1 text-xs font-medium text-on-tertiary-fixed-variant">
                    <span className="h-1.5 w-1.5 rounded-full bg-tertiary" />
                    {T.STATUS_PENDING}
                </span>
            );
        case "pending_renewal":
            return (
                <span className="inline-flex items-center gap-1.5 rounded-full border border-amber-200/50 bg-amber-100 px-2.5 py-1 text-xs font-medium text-amber-700">
                    <span className="h-1.5 w-1.5 rounded-full bg-amber-500" />
                    {T.STATUS_PENDING_RENEWAL || "Chờ duyệt gia hạn"}
                </span>
            );
        default:
            return null;
    }
}

function ActionButtons({
    id,
    status,
    onStatusUpdate,
    onViewDetail,
    onRenewalUpdate,
}: {
    id: string;
    status: BorrowStatus;
    onStatusUpdate: (newStatus: BorrowStatus) => void;
    onViewDetail?: (id: string) => void;
    onRenewalUpdate?: (id: string, approved: boolean) => void;
}) {
    return (
        <div className="flex justify-end gap-1 transition-opacity">
            {/* View detail — available for all */}
            <button
                onClick={() => onViewDetail?.(id)}
                className="rounded p-1.5 text-secondary transition-colors hover:bg-secondary-fixed/50"
                title={T.BTN_VIEW}
            >
                <Eye size={20} />
            </button>
            {/* Context-specific action */}
            {status === "pending" && (
                <button
                    onClick={() => onStatusUpdate("ready")}
                    className="rounded p-1.5 text-primary transition-colors hover:bg-primary-fixed/50"
                    title="Duyệt đơn (Chuyển sang Chờ lấy)"
                >
                    <CheckCircle size={20} />
                </button>
            )}
            {status === "borrowed" && (
                <button
                    onClick={() => onStatusUpdate("returned")}
                    className="rounded p-1.5 text-primary transition-colors hover:bg-primary-fixed/50"
                    title={T.BTN_RETURN}
                >
                    <CheckCircle size={20} />
                </button>
            )}
            {status === "overdue" && (
                <button className="rounded p-1.5 text-error transition-colors hover:bg-error-container/50" title={T.BTN_REMIND}>
                    <Mail size={20} />
                </button>
            )}
            {status === "ready" && (
                <button
                    onClick={() => onStatusUpdate("borrowed")}
                    className="rounded p-1.5 text-primary transition-colors hover:bg-primary-fixed/50"
                    title={T.BTN_CONFIRM_HANDOVER}
                >
                    <PackageCheck size={20} />
                </button>
            )}
            {status === "pending_renewal" && (
                <>
                    <button
                        onClick={() => onRenewalUpdate?.(id, true)}
                        className="text-success hover:bg-success-container/50 rounded p-1.5 transition-colors"
                        title="Duyệt gia hạn"
                    >
                        <CheckCircle size={20} />
                    </button>
                    <button
                        onClick={() => onRenewalUpdate?.(id, false)}
                        className="rounded p-1.5 text-error transition-colors hover:bg-error-container/50"
                        title="Từ chối gia hạn"
                    >
                        <X size={20} />
                    </button>
                </>
            )}
        </div>
    );
}

const AVATAR_COLORS: Record<string, string> = {
    secondary: "bg-secondary-container/20 text-secondary",
    tertiary: "bg-tertiary-container/20 text-tertiary",
    primary: "bg-primary-container/20 text-primary",
};

export default function BorrowTable({
    records,
    onStatusUpdate,
    onViewDetail,
    onRenewalUpdate,
    loading,
    error,
}: {
    records: BorrowRecord[];
    onStatusUpdate?: (id: string, newStatus: BorrowStatus) => void;
    onViewDetail?: (id: string) => void;
    onRenewalUpdate?: (id: string, approved: boolean) => void;
    loading?: boolean;
    error?: string | null;
}) {
    const [currentPage, setCurrentPage] = useState(1);
    const ITEMS_PER_PAGE = 8;

    useEffect(() => {
        setCurrentPage(1);
    }, [records]);

    const totalPages = Math.max(1, Math.ceil(records.length / ITEMS_PER_PAGE));
    const paginatedRecords = records.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

    return (
        <div className="level-1-shadow flex flex-1 flex-col overflow-hidden rounded-xl border border-outline-variant/30 bg-surface-container-lowest">
            <div className="overflow-x-auto">
                <table className="w-full text-left text-sm">
                    {/* Header */}
                    <thead className="border-b border-outline-variant/30 bg-surface-container-low font-label-caps text-label-caps text-on-surface-variant">
                        <tr>
                            <th className="w-[250px] min-w-[250px] px-6 py-4 font-medium">{T.COL_MEMBER}</th>
                            <th className="w-[300px] min-w-[300px] px-6 py-4 font-medium">{T.COL_BOOK}</th>
                            <th className="w-[150px] min-w-[150px] px-6 py-4 font-medium">{T.COL_BORROW_DATE}</th>
                            <th className="w-[150px] min-w-[150px] px-6 py-4 font-medium">{T.COL_DUE_DATE}</th>
                            <th className="w-[150px] min-w-[150px] px-6 py-4 font-medium">{T.COL_STATUS}</th>
                            <th className="w-[120px] min-w-[120px] px-6 py-4 text-right font-medium">{T.COL_ACTIONS}</th>
                        </tr>
                    </thead>

                    {/* Body */}
                    <tbody className="divide-y divide-outline-variant/20">
                        {loading ? (
                            <TableSkeleton columns={6} rows={5} />
                        ) : error ? (
                            <tr>
                                <td colSpan={6} className="px-6 py-12 text-center text-error">
                                    <p>{error}</p>
                                </td>
                            </tr>
                        ) : paginatedRecords.length === 0 ? (
                            <tr>
                                <td colSpan={6} className="px-6 py-12 text-center text-outline-variant">
                                    <div className="flex flex-col items-center justify-center gap-2">
                                        <PackageCheck size={32} className="text-outline-variant" />
                                        <p>{T.EMPTY_STATE}</p>
                                    </div>
                                </td>
                            </tr>
                        ) : (
                            paginatedRecords.map((rec) => (
                                <tr key={rec.id} className="group transition-colors hover:bg-surface-container-low/50">
                                    {/* Member */}
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-3">
                                            {rec.member.avatarUrl ? (
                                                // eslint-disable-next-line @next/next/no-img-element
                                                <img
                                                    src={rec.member.avatarUrl}
                                                    alt={rec.member.name}
                                                    className="h-8 w-8 rounded-full border border-outline-variant/30 object-cover"
                                                />
                                            ) : (
                                                <div
                                                    className={`flex h-8 w-8 items-center justify-center rounded-full text-xs font-bold ${
                                                        AVATAR_COLORS[rec.member.avatarColor ?? "secondary"]
                                                    }`}
                                                >
                                                    {rec.member.avatarInitials}
                                                </div>
                                            )}
                                            <div>
                                                <div className="flex items-center gap-2">
                                                    <p className="font-medium text-on-background">{rec.member.name}</p>
                                                    {rec.isGuest && (
                                                        <span className="rounded bg-primary-100 px-1.5 py-0.5 text-[10px] font-semibold text-primary-700 dark:bg-primary-900 dark:text-primary-300">
                                                            {T.GUEST_BADGE}
                                                        </span>
                                                    )}
                                                </div>
                                                <p className="font-label-caps text-xs text-on-surface-variant">{rec.member.code}</p>
                                            </div>
                                        </div>
                                    </td>

                                    {/* Book */}
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-3">
                                            <div className="relative h-14 w-10 flex-shrink-0 overflow-hidden rounded bg-surface-variant shadow-sm">
                                                {rec.book.coverUrl ? (
                                                    // eslint-disable-next-line @next/next/no-img-element
                                                    <img src={rec.book.coverUrl} alt={rec.book.title} className="h-full w-full object-cover" />
                                                ) : (
                                                    <div className="flex h-full w-full items-center justify-center text-outline-variant">
                                                        <svg
                                                            xmlns="http://www.w3.org/2000/svg"
                                                            width="24"
                                                            height="24"
                                                            viewBox="0 0 24 24"
                                                            fill="none"
                                                            stroke="currentColor"
                                                            strokeWidth="1.5"
                                                            strokeLinecap="round"
                                                            strokeLinejoin="round"
                                                        >
                                                            <path d="M4 19.5v-15A2.5 2.5 0 0 1 6.5 2H20v20H6.5a2.5 2.5 0 0 1 0-5H20" />
                                                        </svg>
                                                    </div>
                                                )}
                                            </div>
                                            <div className="max-w-[200px]">
                                                <p className="truncate font-medium text-on-background">{rec.book.title}</p>
                                                <p className="truncate text-xs text-on-surface-variant">{rec.book.author}</p>
                                            </div>
                                        </div>
                                    </td>

                                    {/* Borrow date */}
                                    <td className={`px-6 py-4 ${rec.borrowDate ? "text-on-surface" : "italic text-on-surface-variant"}`}>
                                        {rec.borrowDate ?? T.NO_DATE}
                                    </td>

                                    {/* Due date */}
                                    <td
                                        className={`px-6 py-4 ${
                                            rec.status === "overdue"
                                                ? "font-medium text-error"
                                                : rec.dueDate
                                                  ? "text-on-surface"
                                                  : "italic text-on-surface-variant"
                                        }`}
                                    >
                                        {rec.dueDate ?? T.NO_DATE}
                                    </td>

                                    {/* Status */}
                                    <td className="px-6 py-4">
                                        <StatusBadge status={rec.status} overdayCount={rec.overdayCount} />
                                    </td>

                                    <td className="px-6 py-4">
                                        <div className="flex justify-end">
                                            <ActionButtons
                                                id={rec.id}
                                                status={rec.status}
                                                onStatusUpdate={(newStatus) => onStatusUpdate?.(rec.id, newStatus)}
                                                onViewDetail={onViewDetail}
                                                onRenewalUpdate={onRenewalUpdate}
                                            />
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="mt-auto flex items-center justify-between border-t border-outline-variant/30 bg-surface-container-lowest px-6 py-4">
                    <p className="font-body-sm text-body-sm text-on-surface-variant">
                        {UI_TEXT.ADMIN_BORROW_MANAGEMENT.FILTERS.PAGINATION_PAGE} {currentPage} / {totalPages}
                    </p>
                    <div className="flex items-center gap-1">
                        <button
                            onClick={() => setCurrentPage((prev) => Math.max(prev - 1, 1))}
                            disabled={currentPage === 1}
                            className="rounded p-1.5 text-on-surface-variant transition-colors hover:bg-surface-container-low disabled:cursor-not-allowed disabled:opacity-50"
                        >
                            <ChevronLeft size={20} />
                        </button>
                        <button
                            onClick={() => setCurrentPage((prev) => Math.min(prev + 1, totalPages))}
                            disabled={currentPage === totalPages}
                            className="rounded p-1.5 text-on-surface-variant transition-colors hover:bg-surface-container-low disabled:cursor-not-allowed disabled:opacity-50"
                        >
                            <ChevronRight size={20} />
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useCallback, useEffect, useState } from "react";
import { Edit2, Loader2, Plus, Tags, Trash2 } from "lucide-react";
import { toast } from "sonner";
import { TableSkeleton } from "@/components/ui/table-skeleton";
import { ADMIN_CATEGORY_MANAGEMENT } from "@/constants/ui-text/admin";
import { categoryService } from "@/services/category";
import type { Category } from "@/types/category";
import CategoryModal from "./CategoryModal";

export default function CategoryTable() {
    const [categories, setCategories] = useState<Category[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingCategory, setEditingCategory] = useState<Category | null>(null);

    const fetchCategories = useCallback(async () => {
        const startTime = Date.now();
        try {
            setLoading(true);
            setError(null);
            const data = await categoryService.getAllCategories();
            setCategories(data);
        } catch (err: any) {
            const elapsed = Date.now() - startTime;
            if (elapsed < 5000) {
                await new Promise((resolve) => setTimeout(resolve, 5000 - elapsed));
            }
            setError(err.message || "Lỗi khi tải danh sách thể loại");
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchCategories();
    }, [fetchCategories]);

    const handleAdd = () => {
        setEditingCategory(null);
        setIsModalOpen(true);
    };

    const handleEdit = (category: Category) => {
        setEditingCategory(category);
        setIsModalOpen(true);
    };

    const [deleteCategoryId, setDeleteCategoryId] = useState<number | null>(null);
    const [isDeleting, setIsDeleting] = useState(false);

    const textUI = ADMIN_CATEGORY_MANAGEMENT;
    const deleteUI = textUI.MODAL;

    const handleDeleteClick = (id: number) => {
        setDeleteCategoryId(id);
    };

    const confirmDelete = async () => {
        if (deleteCategoryId === null) return;

        try {
            setIsDeleting(true);
            await categoryService.deleteCategory(deleteCategoryId);
            fetchCategories();
            setDeleteCategoryId(null);
        } catch (err: any) {
            toast.error(err.message || "Lỗi khi xoá thể loại");
        } finally {
            setIsDeleting(false);
        }
    };

    return (
        <div className="flex h-full flex-col bg-surface">
            {/* Header */}
            <div className="flex items-center justify-between border-b border-surface-container-high bg-white px-8 py-6">
                <div>
                    <h1 className="flex items-center gap-2 text-[28px] font-semibold leading-tight text-ink-950">
                        <Tags size={24} className="text-primary-600" />
                        {textUI.HEADER.TITLE}
                    </h1>
                    <p className="mt-1 text-[14px] text-on-surface-variant">{textUI.HEADER.DESCRIPTION}</p>
                </div>
                <button
                    onClick={handleAdd}
                    className="focus-ring flex items-center gap-2 rounded-lg bg-primary-700 px-4 py-2.5 text-[14px] font-semibold text-white shadow-sm transition-colors hover:bg-primary-500"
                >
                    <Plus size={18} strokeWidth={2.5} />
                    {textUI.HEADER.CREATE_BTN}
                </button>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-auto p-8">
                <div className="overflow-hidden rounded-xl border border-surface-container-high bg-white shadow-sm">
                    <table className="w-full text-left text-[14px]">
                        <thead className="border-b border-surface-container-high bg-surface-container-lowest">
                            <tr>
                                <th className="w-16 px-6 py-4 text-center font-semibold text-on-surface-variant">STT</th>
                                <th className="w-1/3 px-6 py-4 font-semibold text-on-surface-variant">{textUI.TABLE.COL_NAME}</th>
                                <th className="w-1/2 px-6 py-4 font-semibold text-on-surface-variant">{textUI.TABLE.COL_DESC}</th>
                                <th className="px-6 py-4 text-right font-semibold text-on-surface-variant">{textUI.TABLE.COL_ACTIONS}</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-surface-container-high">
                            {loading ? (
                                <TableSkeleton columns={4} rows={5} />
                            ) : error ? (
                                <tr>
                                    <td colSpan={4} className="px-6 py-12 text-center text-error">
                                        <p>{error}</p>
                                        <button onClick={fetchCategories} className="text-primary-600 mt-2 hover:underline">
                                            {textUI.TABLE.BTN_RETRY}
                                        </button>
                                    </td>
                                </tr>
                            ) : categories.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="px-6 py-12 text-center text-outline">
                                        <Tags size={48} className="mx-auto mb-3 text-surface-container-highest" />
                                        <p>{textUI.TABLE.EMPTY_STATE}</p>
                                    </td>
                                </tr>
                            ) : (
                                categories.map((category, index) => (
                                    <tr key={category.id} className="transition-colors hover:bg-surface-container-lowest/50">
                                        <td className="px-6 py-4 text-center text-on-surface-variant">{index + 1}</td>
                                        <td className="px-6 py-4 font-medium text-ink-950">{category.name}</td>
                                        <td className="px-6 py-4 text-on-surface-variant">
                                            {category.description || <span className="italic text-outline-variant">{textUI.TABLE.NO_DESC}</span>}
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center justify-end gap-2">
                                                <button
                                                    onClick={() => handleEdit(category)}
                                                    className="text-primary-600 focus-ring rounded-lg p-2 transition-colors hover:bg-primary-50"
                                                    title="Sửa"
                                                >
                                                    <Edit2 size={16} />
                                                </button>
                                                <button
                                                    onClick={() => handleDeleteClick(category.id)}
                                                    className="focus-ring rounded-lg p-2 text-error transition-colors hover:bg-error-50"
                                                    title="Xoá"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            <CategoryModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} category={editingCategory} onSuccess={fetchCategories} />

            {/* Delete Confirmation Modal */}
            {deleteCategoryId !== null && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-ink-950/40 p-4 backdrop-blur-sm">
                    <div className="w-full max-w-sm overflow-hidden rounded-2xl bg-white shadow-xl">
                        <div className="p-6">
                            <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-error-50 text-error">
                                <Trash2 size={24} />
                            </div>
                            <h3 className="text-center text-lg font-semibold text-ink-950">{deleteUI.DELETE_TITLE}</h3>
                            <p className="mt-2 text-center text-sm text-on-surface-variant">{deleteUI.DELETE_DESC}</p>
                        </div>
                        <div className="flex items-center justify-end gap-3 border-t border-surface-container-high bg-surface-container-lowest px-6 py-4">
                            <button
                                onClick={() => setDeleteCategoryId(null)}
                                className="rounded-lg px-4 py-2 text-sm font-medium text-on-surface-variant transition-colors hover:bg-surface-container-high"
                                disabled={isDeleting}
                            >
                                {deleteUI.DELETE_BTN_CANCEL}
                            </button>
                            <button
                                onClick={confirmDelete}
                                className="flex w-[130px] items-center justify-center gap-2 rounded-lg bg-error px-4 py-2 text-sm font-semibold text-white transition-colors hover:bg-error-600"
                                disabled={isDeleting}
                            >
                                {isDeleting ? <Loader2 size={16} className="animate-spin" /> : "Xóa thể loại"}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { X, Loader2, Save } from "lucide-react";
import CreatableSelect from 'react-select/creatable';
import { bookService } from "@/services/book";
import { categoryService } from "@/services/category";
import { authorService } from "@/services/author";
import type { BookCreateRequest } from "@/types/book";
import type { Category } from "@/types/category";
import type { Author } from "@/types/author";
import { ADMIN } from "@/constants/ui-text/admin";

interface AddBookModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

export default function AddBookModal({ isOpen, onClose, onSuccess }: AddBookModalProps) {
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Form states
  const [title, setTitle] = useState("");
  const [selectedAuthors, setSelectedAuthors] = useState<any[]>([]);
  const [isbn, setIsbn] = useState("");
  const [selectedCategories, setSelectedCategories] = useState<any[]>([]);
  
  const [authorInputValue, setAuthorInputValue] = useState("");
  const [categoryInputValue, setCategoryInputValue] = useState("");
  
  const [shelfLocation, setShelfLocation] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [description, setDescription] = useState("");
  const [publisher, setPublisher] = useState("");
  const [publicationDate, setPublicationDate] = useState("");
  const [pages, setPages] = useState<number | "">("");
  const [depositPrice, setDepositPrice] = useState<number | "">("");

  const [availableCategories, setAvailableCategories] = useState<Category[]>([]);
  const [availableAuthors, setAvailableAuthors] = useState<Author[]>([]);

  const textUI = ADMIN.MODAL.ADD_BOOK;

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const [catData, authData] = await Promise.all([
          categoryService.getAllCategories(),
          authorService.getAllAuthors()
        ]);
        setAvailableCategories(catData);
        setAvailableAuthors(authData);
      } catch (err) {
        console.error("Failed to load reference data:", err);
        setError("Không thể tải danh sách tác giả hoặc thể loại.");
      } finally {
        setLoading(false);
      }
    };
    if (isOpen) {
      loadData();
      // Reset form
      setTitle("");
      setSelectedAuthors([]);
      setIsbn("");
      setSelectedCategories([]);
      setShelfLocation("");
      setImageUrl("");
      setDescription("");
      setPublisher("");
      setPublicationDate("");
      setPages("");
      setDepositPrice("");
      setError(null);
    }
  }, [isOpen]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      setSaving(true);
      setError(null);

      const authorIds = selectedAuthors.filter(a => !a.__isNew__).map(a => Number(a.value));
      const newAuthors = selectedAuthors.filter(a => a.__isNew__).map(a => a.label);

      const categoryIds = selectedCategories.filter(c => !c.__isNew__).map(c => Number(c.value));
      const newCategories = selectedCategories.filter(c => c.__isNew__).map(c => c.label);

      const createData: BookCreateRequest = {
        title,
        authorIds,
        newAuthors,
        isbn,
        categoryIds,
        newCategories,
        shelfLocation,
        imageUrl,
        description,
        publisher,
        publicationDate: publicationDate || undefined,
        pages: pages === "" ? undefined : Number(pages),
        depositPrice: depositPrice === "" ? undefined : Number(depositPrice),
      };

      await bookService.createBook(createData);
      onSuccess();
      onClose();
    } catch (err: any) {
      setError(err.message || textUI.ERROR);
    } finally {
      setSaving(false);
    }
  };

  const authorOptions = availableAuthors.map(a => ({ value: a.id.toString(), label: a.name }));
  const categoryOptions = availableCategories.map(c => ({ value: c.id.toString(), label: c.name }));

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-ink-950/40 p-4 backdrop-blur-sm">
      <div className="relative w-full max-w-2xl overflow-hidden rounded-2xl bg-white shadow-xl max-h-[90vh] flex flex-col">
        <div className="flex items-center justify-between border-b border-surface-container-high px-6 py-4 shrink-0">
          <h2 className="text-[18px] font-semibold text-ink-950">{textUI.TITLE}</h2>
          <button 
            onClick={onClose}
            className="rounded-full p-1.5 text-outline transition-colors hover:bg-surface hover:text-on-surface"
          >
            <X size={20} />
          </button>
        </div>

        <div className="p-6 overflow-y-auto">
          {loading ? (
            <div className="flex py-12 flex-col items-center justify-center gap-3 text-outline">
              <Loader2 size={32} className="animate-spin text-primary-500" />
              <p>Đang tải dữ liệu...</p>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-5">
              {error && (
                <div className="rounded-lg bg-error-50 p-3 text-[14px] text-error">
                  {error}
                </div>
              )}
              
              <div className="grid grid-cols-1 gap-5 sm:grid-cols-2">
                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.TITLE_INPUT}</label>
                  <input 
                    type="text" 
                    required 
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>
                
                <div className="space-y-2">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.AUTHOR_INPUT}</label>
                  <CreatableSelect
                    isMulti
                    options={authorOptions}
                    value={selectedAuthors}
                    inputValue={authorInputValue}
                    onInputChange={(newValue: any) => setAuthorInputValue(newValue)}
                    onChange={(newValue: any) => setSelectedAuthors(newValue as any[])}
                    onBlur={() => {
                      if (authorInputValue.trim()) {
                        setSelectedAuthors([...selectedAuthors, { label: authorInputValue.trim(), value: authorInputValue.trim(), __isNew__: true }]);
                        setAuthorInputValue("");
                      }
                    }}
                    placeholder={textUI.SELECT_AUTHOR_PLACEHOLDER}
                    formatCreateLabel={(inputValue: string) => `${textUI.CREATE_AUTHOR} "${inputValue}"`}
                    noOptionsMessage={() => textUI.NO_AUTHOR_FOUND}
                    className="text-[14px]"
                    styles={{
                      control: (base: any) => ({
                        ...base,
                        borderRadius: '0.5rem',
                        borderColor: '#E2E8F0',
                        padding: '2px',
                        boxShadow: 'none',
                        '&:hover': { borderColor: '#16a34a' }
                      }),
                      option: (base: any) => ({ ...base, fontSize: '13px' }),
                      multiValue: (base: any) => ({ ...base, backgroundColor: '#f1f5f9', borderRadius: '4px' })
                    }}
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.ISBN_INPUT}</label>
                  <input 
                    type="text" 
                    value={isbn}
                    onChange={(e) => setIsbn(e.target.value)}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] font-mono focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.CATEGORY_INPUT}</label>
                  <CreatableSelect
                    isMulti
                    options={categoryOptions}
                    value={selectedCategories}
                    inputValue={categoryInputValue}
                    onInputChange={(newValue: any) => setCategoryInputValue(newValue)}
                    onChange={(newValue: any) => setSelectedCategories(newValue as any[])}
                    onBlur={() => {
                      if (categoryInputValue.trim()) {
                        setSelectedCategories([...selectedCategories, { label: categoryInputValue.trim(), value: categoryInputValue.trim(), __isNew__: true }]);
                        setCategoryInputValue("");
                      }
                    }}
                    placeholder={textUI.SELECT_CATEGORY_PLACEHOLDER}
                    formatCreateLabel={(inputValue: string) => `${textUI.CREATE_CATEGORY} "${inputValue}"`}
                    noOptionsMessage={() => textUI.NO_CATEGORY_FOUND}
                    className="text-[14px]"
                    styles={{
                      control: (base: any) => ({
                        ...base,
                        borderRadius: '0.5rem',
                        borderColor: '#E2E8F0',
                        padding: '2px',
                        boxShadow: 'none',
                        '&:hover': { borderColor: '#16a34a' }
                      }),
                      option: (base: any) => ({ ...base, fontSize: '13px' }),
                      multiValue: (base: any) => ({ ...base, backgroundColor: '#f1f5f9', borderRadius: '4px' })
                    }}
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.PUBLISHER_INPUT}</label>
                  <input 
                    type="text" 
                    value={publisher}
                    onChange={(e) => setPublisher(e.target.value)}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.PUBLICATION_DATE_INPUT}</label>
                  <input 
                    type="date" 
                    value={publicationDate}
                    onChange={(e) => setPublicationDate(e.target.value)}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.PAGES_INPUT}</label>
                  <input 
                    type="number" 
                    value={pages}
                    onChange={(e) => setPages(e.target.value === "" ? "" : Number(e.target.value))}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.DEPOSIT_PRICE_INPUT}</label>
                  <input 
                    type="number" 
                    value={depositPrice}
                    onChange={(e) => setDepositPrice(e.target.value === "" ? "" : Number(e.target.value))}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.SHELF_LOCATION_INPUT}</label>
                  <input 
                    type="text" 
                    value={shelfLocation}
                    onChange={(e) => setShelfLocation(e.target.value)}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>
              </div>

              <div className="space-y-1.5 border-t border-surface-container-high pt-5 mt-5">
                <label className="text-[13px] font-medium text-on-surface-variant">{textUI.DESCRIPTION_INPUT}</label>
                <textarea 
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] min-h-[80px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[13px] font-medium text-on-surface-variant">{textUI.IMAGE_URL_INPUT}</label>
                <input 
                  type="url" 
                  value={imageUrl}
                  onChange={(e) => setImageUrl(e.target.value)}
                  className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                />
              </div>

              <div className="flex items-center justify-end gap-3 pt-4">
                <button 
                  type="button" 
                  onClick={onClose}
                  className="rounded-lg px-4 py-2.5 text-[14px] font-medium text-on-surface-variant hover:bg-surface transition-colors"
                >
                  {textUI.CANCEL}
                </button>
                <button 
                  type="submit" 
                  disabled={saving}
                  className="flex items-center gap-2 rounded-lg bg-primary-700 px-5 py-2.5 text-[14px] font-semibold text-white transition-colors hover:bg-primary-500 disabled:opacity-70 focus-ring"
                >
                  {saving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                  {textUI.SUBMIT}
                </button>
              </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import { Book, ChevronLeft, ChevronRight, Library, MoreVertical, Pencil, Trash2 } from "lucide-react";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { toast } from "sonner";
import { TableSkeleton } from "@/components/ui/table-skeleton";
import { ADMIN_INVENTORY_MANAGEMENT } from "@/constants/ui-text/admin";
import { bookService } from "@/services/book";
import type { BookListItem, PageResponse } from "@/types/book";
import BookCopiesModal from "./BookCopiesModal";
import EditBookModal from "./EditBookModal";

const textUI = ADMIN_INVENTORY_MANAGEMENT;

const CoverPlaceholder = () => {
    return (
        <div className="flex h-16 w-12 shrink-0 items-center justify-center overflow-hidden rounded bg-surface-container-high text-outline">
            <Book size={18} />
        </div>
    );
};

interface TableRowProps {
    book: BookListItem;
    onEdit: (id: number) => void;
    onManageCopies: (id: number, title: string) => void;
}

const TableRow = ({ book, onEdit, onManageCopies }: TableRowProps) => {
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const menuRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setIsMenuOpen(false);
            }
        };

        if (isMenuOpen) {
            document.addEventListener("mousedown", handleClickOutside);
        }
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, [isMenuOpen]);

    return (
        <tr className="transition-colors hover:bg-surface/30">
            <td className="px-6 py-4">
                {book.imageUrl ? (
                    <div className="flex h-16 w-12 shrink-0 items-center justify-center overflow-hidden rounded bg-surface-container-high text-outline">
                        {/* eslint-disable-next-line @next/next/no-img-element */}
                        <img src={book.imageUrl} alt={book.title} className="h-full w-full object-cover" />
                    </div>
                ) : (
                    <CoverPlaceholder />
                )}
            </td>
            <td className="px-6 py-4">
                <div className="max-w-[200px]">
                    <p className="mb-1 font-semibold leading-tight text-ink-950">{book.title}</p>
                    <p className="text-[13px] text-on-surface-variant">
                        {book.authors && book.authors.length > 0 ? (
                            book.authors.map((a) => a.name).join(", ")
                        ) : (
                            <span className="italic">{textUI.TABLE.NOT_UPDATED}</span>
                        )}
                    </p>
                </div>
            </td>
            <td className="px-6 py-4 font-mono text-[13px] text-on-surface-variant">{book.isbn || "N/A"}</td>
            <td className="px-6 py-4">
                {book.categories && book.categories.length > 0 ? (
                    <div className="flex max-w-[150px] flex-wrap gap-1">
                        {book.categories.map((cat) => (
                            <span
                                key={cat.id}
                                className="truncate rounded-md border border-surface-container-high bg-surface px-2 py-0.5 text-[12px] font-medium text-on-surface-variant"
                                title={cat.name}
                            >
                                {cat.name}
                            </span>
                        ))}
                    </div>
                ) : (
                    <span className="text-[13px] italic text-outline-variant">{textUI.TABLE.NA}</span>
                )}
            </td>
            <td className="px-6 py-4 text-center">
                <div className="inline-flex items-center gap-1.5 rounded-full border border-surface-container-high bg-surface-container-low px-3 py-1 text-[14px] font-medium text-on-surface">
                    <span className="text-primary-600">{book.availableQuantity}</span>
                    <span className="text-outline-variant">/</span>
                    <span>{book.quantity || 0}</span>
