            </td>
            <td className="px-6 py-4">
                <p className="text-[13px] leading-tight text-on-surface-variant">
                    {book.shelfLocation
                        ? book.shelfLocation.split(", ").map((loc, idx) => (
                              <span key={idx} className="block">
                                  {loc}
                              </span>
                          ))
                        : "Chưa xếp giá"}
                </p>
            </td>
            <td className="px-6 py-4 text-center">
                <div className="relative inline-block text-left" ref={menuRef}>
                    <button
                        onClick={() => setIsMenuOpen(!isMenuOpen)}
                        className="focus-ring rounded p-1.5 text-outline transition-colors hover:bg-surface hover:text-on-surface"
                    >
                        <MoreVertical size={18} />
                    </button>

                    {isMenuOpen && (
                        <div className="absolute right-0 z-10 mt-1 w-48 origin-top-right rounded-md bg-white shadow-lg ring-1 ring-black ring-opacity-5 focus:outline-none">
                            <div className="py-1">
                                <button
                                    onClick={() => {
                                        setIsMenuOpen(false);
                                        onManageCopies(book.id, book.title);
                                    }}
                                    className="group flex w-full items-center gap-2 px-4 py-2 text-sm text-on-surface transition-colors hover:bg-surface"
                                >
                                    <Library size={15} className="group-hover:text-primary-600 text-outline" />
                                    {textUI.TABLE.BTN_COPIES}
                                </button>
                                <div className="my-1 border-t border-surface-container-high"></div>
                                <button
                                    onClick={() => {
                                        setIsMenuOpen(false);
                                        onEdit(book.id);
                                    }}
                                    className="group flex w-full items-center gap-2 px-4 py-2 text-sm text-on-surface transition-colors hover:bg-surface"
                                >
                                    <Pencil size={15} className="group-hover:text-primary-600 text-outline" />
                                    {textUI.TABLE.BTN_EDIT}
                                </button>
                                <button
                                    onClick={() => {
                                        setIsMenuOpen(false);
                                        toast.info("Chức năng xóa sách đang phát triển");
                                    }}
                                    className="group flex w-full items-center gap-2 px-4 py-2 text-sm text-error transition-colors hover:bg-error-50"
                                >
                                    <Trash2 size={15} className="text-error-400 group-hover:text-error" />
                                    {textUI.TABLE.BTN_DELETE}
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </td>
        </tr>
    );
};

export default function BookTable() {
    const [data, setData] = useState<PageResponse<BookListItem> | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const searchParams = useSearchParams();
    const router = useRouter();
    const pathname = usePathname();

    // URL State
    const page = parseInt(searchParams?.get("page") || "0", 10);
    const keyword = searchParams?.get("keyword") || undefined;
    const category = searchParams?.get("category") || undefined;

    // Edit Modal State
    const [editBookId, setEditBookId] = useState<number | null>(null);
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);

    // Copies Modal State
    const [copiesBookId, setCopiesBookId] = useState<number | null>(null);
    const [copiesBookTitle, setCopiesBookTitle] = useState<string>("");
    const [isCopiesModalOpen, setIsCopiesModalOpen] = useState(false);

    const fetchData = useCallback(async () => {
        const startTime = Date.now();
        try {
            setLoading(true);
            setError(null);
            // We no longer pass status since it's removed from filters
            const result = await bookService.getAdminBookInventory(page, 10, keyword, category);
            setData(result);
        } catch (err: any) {
            const elapsed = Date.now() - startTime;
            if (elapsed < 5000) {
                await new Promise((resolve) => setTimeout(resolve, 5000 - elapsed));
            }
            setError(err.message || "Lỗi khi tải dữ liệu");
        } finally {
            setLoading(false);
        }
    }, [page, keyword, category]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleEditClick = (id: number) => {
        setEditBookId(id);
        setIsEditModalOpen(true);
    };

    const handleManageCopiesClick = (id: number, title: string) => {
        setCopiesBookId(id);
        setCopiesBookTitle(title);
        setIsCopiesModalOpen(true);
    };

    const handleEditSuccess = () => {
        fetchData(); // refresh list
    };

    const createPageUrl = (newPage: number) => {
        const params = new URLSearchParams(searchParams?.toString() || "");
        params.set("page", newPage.toString());
        return `${pathname}?${params.toString()}`;
    };

    const setPage = (newPage: number) => {
        router.push(createPageUrl(newPage));
    };

    return (
        <>
            <div className="flex flex-col rounded-xl border border-surface-container-high bg-white shadow-sm">
                <div className="min-h-[400px] overflow-x-auto">
                    <table className="w-full text-left text-[14px]">
                        <thead className="border-b border-surface-container-high bg-surface/50 font-label-caps text-[12px] uppercase tracking-wider text-on-surface-variant">
                            <tr>
                                <th className="px-6 py-4 font-medium">{textUI.TABLE.COL_COVER}</th>
                                <th className="px-6 py-4 font-medium">{textUI.TABLE.COL_TITLE}</th>
                                <th className="px-6 py-4 font-medium">{textUI.TABLE.COL_ISBN}</th>
                                <th className="px-6 py-4 font-medium">{textUI.TABLE.COL_CATEGORY}</th>
                                <th className="px-6 py-4 text-center font-medium">{textUI.TABLE.COL_STOCK}</th>
                                <th className="px-6 py-4 font-medium">{textUI.TABLE.COL_LOCATION}</th>
                                <th className="px-6 py-4 text-center font-medium">{textUI.TABLE.COL_ACTIONS}</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-surface-container-high text-on-surface">
                            {loading ? (
                                <TableSkeleton columns={7} rows={5} />
                            ) : error ? (
                                <tr>
                                    <td colSpan={7} className="px-6 py-12 text-center text-error">
                                        <p>{error}</p>
                                    </td>
                                </tr>
                            ) : data?.content.length === 0 ? (
                                <tr>
                                    <td colSpan={7} className="px-6 py-12 text-center text-outline">
                                        <p>{textUI.TABLE.EMPTY_STATE}</p>
                                    </td>
                                </tr>
                            ) : (
                                data?.content.map((book) => (
                                    <TableRow key={book.id} book={book} onEdit={handleEditClick} onManageCopies={handleManageCopiesClick} />
                                ))
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Pagination Footer */}
                <div className="flex items-center justify-between border-t border-surface-container-high px-6 py-4 text-[13px] text-on-surface-variant">
                    <span>
                        {loading || !data
                            ? "Đang tải..."
                            : `Hiển thị ${data.number * data.size + 1} đến ${Math.min((data.number + 1) * data.size, data.totalElements)} của ${data.totalElements} mục`}
                    </span>
                    <div className="flex items-center gap-1">
                        <button
                            disabled={loading || !data || data.first}
                            onClick={() => setPage(Math.max(0, page - 1))}
                            className="focus-ring flex h-8 w-8 items-center justify-center rounded border border-surface-container-high bg-white text-outline transition-colors hover:bg-surface hover:text-on-surface disabled:opacity-50 disabled:hover:bg-white"
                        >
                            <ChevronLeft size={16} />
                        </button>
                        <button
                            disabled={loading || !data || data.last}
                            onClick={() => setPage(page + 1)}
                            className="focus-ring flex h-8 w-8 items-center justify-center rounded border border-surface-container-high bg-white text-outline transition-colors hover:bg-surface hover:text-on-surface disabled:opacity-50 disabled:hover:bg-white"
                        >
                            <ChevronRight size={16} />
                        </button>
                    </div>
                </div>
            </div>

            {isEditModalOpen && editBookId !== null && (
                <EditBookModal bookId={editBookId} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSuccess={handleEditSuccess} />
            )}

            {isCopiesModalOpen && copiesBookId !== null && (
                <BookCopiesModal
                    bookId={copiesBookId}
                    bookTitle={copiesBookTitle}
                    isOpen={isCopiesModalOpen}
                    onClose={() => setIsCopiesModalOpen(false)}
                    onSuccess={handleEditSuccess}
                />
            )}
        </>
    );
}

"use client";

import { useState, useEffect } from "react";
import { X, Loader2, Save } from "lucide-react";
import CreatableSelect from 'react-select/creatable';
import { bookService } from "@/services/book";
import { categoryService } from "@/services/category";
import { authorService } from "@/services/author";
import type { Book, BookUpdateRequest } from "@/types/book";
import type { Category } from "@/types/category";
import type { Author } from "@/types/author";
import { ADMIN } from "@/constants/ui-text/admin";

interface EditBookModalProps {
  bookId: number;
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

export default function EditBookModal({ bookId, isOpen, onClose, onSuccess }: EditBookModalProps) {
  const [book, setBook] = useState<Book | null>(null);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Form states
  const [title, setTitle] = useState("");
  const [selectedAuthors, setSelectedAuthors] = useState<any[]>([]);
  const [isbn, setIsbn] = useState("");
  const [selectedCategories, setSelectedCategories] = useState<any[]>([]);

  const [authorInputValue, setAuthorInputValue] = useState("");
  const [categoryInputValue, setCategoryInputValue] = useState("");

  const [shelfLocation, setShelfLocation] = useState("");
  const [imageUrl, setImageUrl] = useState("");

  const [quantity, setQuantity] = useState<number>(0);
  const [availableQuantity, setAvailableQuantity] = useState<number>(0);

  const [availableCategories, setAvailableCategories] = useState<Category[]>([]);
  const [availableAuthors, setAvailableAuthors] = useState<Author[]>([]);

  const textUI = ADMIN.MODAL.EDIT_BOOK;

  useEffect(() => {
    const loadData = async () => {
      try {
        const [catData, authData] = await Promise.all([
          categoryService.getAllCategories(),
          authorService.getAllAuthors()
        ]);
        setAvailableCategories(catData);
        setAvailableAuthors(authData);
      } catch (err) {
        console.error("Failed to load reference data:", err);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (isOpen && bookId) {
      fetchBookDetails();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen, bookId]);

  const fetchBookDetails = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await bookService.getBookById(bookId);
      setBook(data);
      
      setTitle(data.title || "");
      setSelectedAuthors(data.authors?.map(a => ({ value: a.id.toString(), label: a.name })) || []);
      setIsbn(data.isbn || "");
      setSelectedCategories(data.categories?.map(c => ({ value: c.id.toString(), label: c.name })) || []);

      setShelfLocation(data.shelfLocation || "");
      setImageUrl(data.imageUrl || "");
      setQuantity(data.quantity || 0);
      setAvailableQuantity(data.availableQuantity || 0);
    } catch (err: any) {
      setError(err.message || "Lỗi khi tải thông tin sách");
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      setSaving(true);
      setError(null);

      const authorIds = selectedAuthors.filter(a => !a.__isNew__).map(a => Number(a.value));
      const newAuthors = selectedAuthors.filter(a => a.__isNew__).map(a => a.label);

      const categoryIds = selectedCategories.filter(c => !c.__isNew__).map(c => Number(c.value));
      const newCategories = selectedCategories.filter(c => c.__isNew__).map(c => c.label);

      const updateData: BookUpdateRequest = {
        title,
        authorIds,
        newAuthors,
        isbn,
        categoryIds,
        newCategories,

        shelfLocation,
        imageUrl,
        quantity,
        availableQuantity,
      };

      await bookService.updateBook(bookId, updateData);
      onSuccess();
      onClose();
    } catch (err: any) {
      setError(err.message || "Lỗi khi lưu sách");
    } finally {
      setSaving(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-ink-950/40 p-4 backdrop-blur-sm">
      <div className="relative w-full max-w-2xl overflow-hidden rounded-2xl bg-white shadow-xl max-h-[90vh] flex flex-col">
        <div className="flex items-center justify-between border-b border-surface-container-high px-6 py-4 shrink-0">
          <h2 className="text-[18px] font-semibold text-ink-950">{textUI.TITLE}</h2>
          <button 
            onClick={onClose}
            className="rounded-full p-1.5 text-outline transition-colors hover:bg-surface hover:text-on-surface"
          >
            <X size={20} />
          </button>
        </div>

        <div className="p-6 overflow-y-auto">
          {loading ? (
            <div className="flex py-12 flex-col items-center justify-center gap-3 text-outline">
              <Loader2 size={32} className="animate-spin text-primary-500" />
              <p>Đang tải dữ liệu...</p>
            </div>
          ) : error && !book ? (
            <div className="py-12 text-center text-error">
              <p>{error}</p>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-5">
              {error && (
                <div className="rounded-lg bg-error-50 p-3 text-[14px] text-error">
                  {error}
                </div>
              )}
              
              <div className="grid grid-cols-1 gap-5 sm:grid-cols-2">
                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.TITLE_INPUT}</label>
                  <input 
                    type="text" 
                    required 
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>
                
                <div className="space-y-2">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.AUTHOR_INPUT}</label>
                  <CreatableSelect
                    isMulti
                    options={availableAuthors.map(a => ({ value: a.id.toString(), label: a.name }))}
                    value={selectedAuthors}
                    inputValue={authorInputValue}
                    onInputChange={(newValue: any) => setAuthorInputValue(newValue)}
                    onChange={(newValue: any) => setSelectedAuthors(newValue as any[])}
                    onBlur={() => {
                      if (authorInputValue.trim()) {
                        setSelectedAuthors([...selectedAuthors, { label: authorInputValue.trim(), value: authorInputValue.trim(), __isNew__: true }]);
                        setAuthorInputValue("");
                      }
                    }}
                    placeholder={textUI.SELECT_AUTHOR_PLACEHOLDER}
                    formatCreateLabel={(inputValue: string) => `${textUI.CREATE_AUTHOR} "${inputValue}"`}
                    noOptionsMessage={() => textUI.NO_AUTHOR_FOUND}
                    className="text-[14px]"
                    styles={{
                      control: (base: any) => ({
                        ...base,
                        borderRadius: '0.5rem',
                        borderColor: '#E2E8F0',
                        padding: '2px',
                        boxShadow: 'none',
                        '&:hover': { borderColor: '#16a34a' }
                      }),
                      option: (base: any) => ({ ...base, fontSize: '13px' }),
                      multiValue: (base: any) => ({ ...base, backgroundColor: '#f1f5f9', borderRadius: '4px' })
                    }}
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.ISBN_INPUT}</label>
                  <input 
                    type="text" 
                    value={isbn}
                    onChange={(e) => setIsbn(e.target.value)}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] font-mono focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.CATEGORY_INPUT}</label>
                  <CreatableSelect
                    isMulti
                    options={availableCategories.map(c => ({ value: c.id.toString(), label: c.name }))}
                    value={selectedCategories}
                    inputValue={categoryInputValue}
                    onInputChange={(newValue: any) => setCategoryInputValue(newValue)}
                    onChange={(newValue: any) => setSelectedCategories(newValue as any[])}
                    onBlur={() => {
                      if (categoryInputValue.trim()) {
                        setSelectedCategories([...selectedCategories, { label: categoryInputValue.trim(), value: categoryInputValue.trim(), __isNew__: true }]);
                        setCategoryInputValue("");
                      }
                    }}
                    placeholder={textUI.SELECT_CATEGORY_PLACEHOLDER}
                    formatCreateLabel={(inputValue: string) => `${textUI.CREATE_CATEGORY} "${inputValue}"`}
                    noOptionsMessage={() => textUI.NO_CATEGORY_FOUND}
                    className="text-[14px]"
                    styles={{
                      control: (base: any) => ({
                        ...base,
                        borderRadius: '0.5rem',
                        borderColor: '#E2E8F0',
                        padding: '2px',
                        boxShadow: 'none',
                        '&:hover': { borderColor: '#16a34a' }
                      }),
                      option: (base: any) => ({ ...base, fontSize: '13px' }),
                      multiValue: (base: any) => ({ ...base, backgroundColor: '#f1f5f9', borderRadius: '4px' })
                    }}
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.QUANTITY_TOTAL}</label>
                  <input 
                    type="number" 
                    value={quantity}
                    disabled
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] bg-surface-container-low cursor-not-allowed text-on-surface-variant"
                  />
                  <p className="text-[11px] text-outline">{textUI.QUANTITY_AUTO_NOTE}</p>
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.QUANTITY_AVAILABLE}</label>
                  <input 
                    type="number" 
                    value={availableQuantity}
                    disabled
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] bg-surface-container-low cursor-not-allowed text-on-surface-variant"
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[13px] font-medium text-on-surface-variant">{textUI.SHELF_LOCATION_INPUT}</label>
                  <input 
                    type="text" 
                    value={shelfLocation}
                    onChange={(e) => setShelfLocation(e.target.value)}
                    className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                  />
                </div>
              </div>

              <div className="space-y-1.5 border-t border-surface-container-high pt-5 mt-5">
                <label className="text-[13px] font-medium text-on-surface-variant">{textUI.IMAGE_URL_INPUT}</label>
                <input 
                  type="url" 
                  value={imageUrl}
                  onChange={(e) => setImageUrl(e.target.value)}
                  className="w-full rounded-lg border border-surface-container-high px-3 py-2 text-[14px] focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                />
              </div>

              <div className="flex items-center justify-end gap-3 pt-4">
                <button 
                  type="button" 
                  onClick={onClose}
                  className="rounded-lg px-4 py-2.5 text-[14px] font-medium text-on-surface-variant hover:bg-surface transition-colors"
                >
                  {textUI.CANCEL}
                </button>
                <button 
                  type="submit" 
                  disabled={saving}
                  className="flex items-center gap-2 rounded-lg bg-primary-700 px-5 py-2.5 text-[14px] font-semibold text-white transition-colors hover:bg-primary-500 disabled:opacity-70 focus-ring"
                >
                  {saving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                  {textUI.SUBMIT}
                </button>
              </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { BookOpen, Lock, Mail, ShieldAlert, User as UserIcon, X } from "lucide-react";
import { UI_TEXT } from "@/constants/ui-text";
import type { User } from "@/types/user";

interface UserModalProps {
    open: boolean;
    onClose: () => void;
    initialData?: User | null;
    onSave?: (data: { name: string; email: string; role: string; password?: string }) => Promise<void>;
}

export default function UserModal({ open, onClose, initialData, onSave }: UserModalProps) {
    const [form, setForm] = useState({
        name: "",
        email: "",
        password: "",
        role: "customer",
    });
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const isEditMode = !!initialData;
    const initialRole = initialData?.role?.toLowerCase();

    // Reset form when modal opens
    useEffect(() => {
        if (open) {
            setForm({
                name: initialData?.name || "",
                email: initialData?.email || "",
                password: "",
                role: initialRole || "customer",
            });
            setError(null);
        }
    }, [open, initialData, initialRole]);

    if (!open) return null;

    const handleSave = async () => {
        setError(null);
        if (!form.name.trim()) {
            setError("Tên không được để trống");
            return;
        }
        if (!isEditMode && !form.email.trim()) {
            setError("Email không được để trống");
            return;
        }
        if (!isEditMode && form.password.length < 8) {
            setError("Mật khẩu phải có ít nhất 8 ký tự");
            return;
        }

        setIsSaving(true);
        try {
            if (onSave) {
                await onSave(form);
            }
            onClose();
        } catch (error: any) {
            console.error("Failed to save user", error);
            setError(error?.response?.data?.message || "Lưu thông tin thất bại");
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-on-background/40 px-4 backdrop-blur-sm">
            <div className="level-2-shadow flex w-full max-w-lg transform flex-col overflow-hidden rounded-2xl bg-surface-container-lowest transition-all">
                {/* Header */}
                <div className="flex items-center justify-between border-b border-outline-variant/30 bg-surface-bright p-lg">
                    <h3 className="font-headline-lg text-headline-lg-mobile text-on-background">
                        {isEditMode ? "Chỉnh sửa thành viên" : UI_TEXT.ADMIN_USER_MANAGEMENT.MODAL.CREATE_TITLE}
                    </h3>
                    <button
                        onClick={onClose}
                        className="rounded-full p-1 text-on-surface-variant transition-colors hover:bg-error-container/20 hover:text-error"
                        title={UI_TEXT.ADMIN_USER_MANAGEMENT.MODAL.CLOSE}
                    >
                        <X size={24} />
                    </button>
                </div>

                {/* Form Body */}
                <div className="flex flex-col gap-md p-lg">
                    {error && <div className="rounded-lg border border-error/30 bg-error-container/20 p-3 text-sm font-medium text-error">{error}</div>}

                    <div className="flex flex-col gap-1.5">
